"""Factory functions for creating sample trajectories for testing.

Provides utilities to create TokenTrajectory and GeneratedTrajectory instances
with configurable parameters for various test scenarios.
"""

from __future__ import annotations

import math
from dataclasses import dataclass
from typing import Sequence

import torch

from src.common.token_trajectory import TokenTrajectory
from src.inference.generated_trajectory import GeneratedTrajectory


def create_sample_trajectory(
    n_tokens: int = 10,
    prefill_text: str = "",
    generated_text: str = "Sample generated text",
    arm_idx: tuple[int, ...] | None = None,
    base_token_id: int = 100,
    logprob_range: tuple[float, float] = (-2.0, -0.5),
) -> TokenTrajectory:
    """Create a sample TokenTrajectory for testing.

    Args:
        n_tokens: Total number of tokens in the sequence
        prefill_text: Text prepended before generation
        generated_text: Text generated by the model
        arm_idx: Tuple of arm indices this trajectory belongs to
        base_token_id: Starting token ID (increments from here)
        logprob_range: Range for random logprobs (min, max)

    Returns:
        TokenTrajectory with the specified parameters
    """
    token_ids = [base_token_id + i for i in range(n_tokens)]

    # First token has logprob 0 (given)
    min_lp, max_lp = logprob_range
    logprobs = [0.0]
    for i in range(1, n_tokens):
        # Deterministic "random" logprobs based on position
        lp = min_lp + (max_lp - min_lp) * ((i * 13) % 7) / 7
        logprobs.append(lp)

    # Logits approximated as logprobs
    logits = logprobs.copy()

    return TokenTrajectory(
        token_ids=token_ids,
        logprobs=logprobs,
        logits=logits,
        prefill_text=prefill_text,
        generated_text=generated_text,
        arm_idx=arm_idx,
    )


def create_divergent_trajectories(
    n_trajectories: int = 3,
    diverge_at: int = 5,
    total_length: int = 10,
    prefix_tokens: list[int] | None = None,
) -> list[TokenTrajectory]:
    """Create multiple trajectories that share a prefix and diverge.

    Useful for testing tree building and branching node detection.

    Args:
        n_trajectories: Number of trajectories to create
        diverge_at: Position where trajectories start diverging
        total_length: Total length of each trajectory
        prefix_tokens: Shared prefix tokens (auto-generated if None)

    Returns:
        List of TokenTrajectory instances that share tokens up to diverge_at
    """
    if prefix_tokens is None:
        prefix_tokens = [100 + i for i in range(diverge_at)]

    trajectories = []
    for traj_idx in range(n_trajectories):
        # Shared prefix
        token_ids = prefix_tokens.copy()

        # Divergent suffix - each trajectory gets different tokens
        for pos in range(diverge_at, total_length):
            token_ids.append(1000 + traj_idx * 100 + pos)

        # Generate logprobs
        logprobs = [0.0]  # First token is given
        for i in range(1, total_length):
            logprobs.append(-1.0 - (i * 0.1))

        traj = TokenTrajectory(
            token_ids=token_ids,
            logprobs=logprobs,
            logits=logprobs.copy(),
            prefill_text=f"prefix_{traj_idx}",
            generated_text=f"generated_{traj_idx}",
            arm_idx=(traj_idx,),
        )
        trajectories.append(traj)

    return trajectories


def create_trajectory_with_full_logits(
    n_tokens: int = 10,
    vocab_size: int = 1000,
) -> GeneratedTrajectory:
    """Create a GeneratedTrajectory with full_logits tensor.

    Args:
        n_tokens: Number of tokens in the sequence
        vocab_size: Size of vocabulary for logits

    Returns:
        GeneratedTrajectory with full_logits populated
    """
    token_ids = [100 + i for i in range(n_tokens)]
    logits = torch.randn(n_tokens, vocab_size)

    return GeneratedTrajectory.from_inference(
        token_ids=token_ids,
        logits=logits,
        device="cpu",
    )


def create_trajectory_pair_for_fork(
    shared_length: int = 5,
    total_length: int = 10,
    arm_indices: tuple[tuple[int, ...], tuple[int, ...]] = ((0,), (1,)),
) -> tuple[TokenTrajectory, TokenTrajectory]:
    """Create a pair of trajectories for testing fork creation.

    Args:
        shared_length: Number of shared prefix tokens
        total_length: Total length of each trajectory
        arm_indices: Arm indices for each trajectory

    Returns:
        Tuple of two TokenTrajectory instances that diverge at shared_length
    """
    shared_tokens = [100 + i for i in range(shared_length)]

    # First trajectory
    tokens_a = shared_tokens + [200 + i for i in range(total_length - shared_length)]
    logprobs_a = [0.0] + [-1.0 - i * 0.1 for i in range(total_length - 1)]

    traj_a = TokenTrajectory(
        token_ids=tokens_a,
        logprobs=logprobs_a,
        logits=logprobs_a.copy(),
        arm_idx=arm_indices[0],
    )

    # Second trajectory - different tokens after shared_length
    tokens_b = shared_tokens + [300 + i for i in range(total_length - shared_length)]
    logprobs_b = [0.0] + [-1.2 - i * 0.1 for i in range(total_length - 1)]

    traj_b = TokenTrajectory(
        token_ids=tokens_b,
        logprobs=logprobs_b,
        logits=logprobs_b.copy(),
        arm_idx=arm_indices[1],
    )

    return traj_a, traj_b


@dataclass
class TrajectoryBatch:
    """Collection of related trajectories for testing."""

    trajectories: list[TokenTrajectory]
    groups_per_traj: list[tuple[int, ...]]
    fork_arms: list[tuple[int, int]]

    @property
    def n_trajectories(self) -> int:
        return len(self.trajectories)


def create_trajectory_batch(
    n_groups: int = 2,
    trajs_per_group: int = 3,
    shared_length: int = 5,
    total_length: int = 10,
) -> TrajectoryBatch:
    """Create a batch of trajectories organized into groups.

    Args:
        n_groups: Number of trajectory groups
        trajs_per_group: Trajectories per group
        shared_length: Shared prefix length across all trajectories
        total_length: Total trajectory length

    Returns:
        TrajectoryBatch with trajectories, group assignments, and fork arms
    """
    shared_tokens = [100 + i for i in range(shared_length)]

    trajectories = []
    groups_per_traj = []

    for group in range(n_groups):
        for traj_num in range(trajs_per_group):
            # Each group diverges differently after shared_length
            suffix = [
                1000 + group * 100 + traj_num * 10 + i
                for i in range(total_length - shared_length)
            ]
            token_ids = shared_tokens + suffix

            logprobs = [0.0] + [
                -1.0 - i * 0.1 for i in range(total_length - 1)
            ]

            traj = TokenTrajectory(
                token_ids=token_ids,
                logprobs=logprobs,
                logits=logprobs.copy(),
                arm_idx=(group,),
            )
            trajectories.append(traj)
            groups_per_traj.append((group,))

    # Create fork arms between all group pairs
    fork_arms = []
    for i in range(n_groups):
        for j in range(i + 1, n_groups):
            fork_arms.append((i, j))

    return TrajectoryBatch(
        trajectories=trajectories,
        groups_per_traj=groups_per_traj,
        fork_arms=fork_arms,
    )
